('VHL_2021_consolidated_inventory_4', 'VHL', 2021, 'consolidated', 'Hàng hóa', 'finished_goods', 7267771630.0, 508068300.0, 'Hàng hóa kinh doanh thương mại'),
('VHL_2021_consolidated_inventory_5', 'VHL', 2021, 'consolidated', 'Chi phí ban đầu mỏ đất sét Xích Thổ', 'real_estate_project', 18567166802.0, 0.0, 'Chi phí cấp quyền khai thác, đền bù giải phóng mặt bằng và các chi phí phát sinh ban đầu tại mỏ sét Xích Thổ. Tại thời điểm báo cáo, mỏ chưa được đưa vào hoạt động khai thác.'),
('VHL_2021_consolidated_inventory_6', 'VHL', 2021, 'consolidated', 'Dự án Khu tái định cư và nhà ở CBCNV nhà máy gạch Tuynel tại xã Lê Lợi, huyện Hoành Bồ', 'real_estate_project', 33642634419.0, 16754634419.0, 'Dự án triển khai từ năm 2009, bị dừng hoạt động theo Quyết định số 3791/QĐ-KHĐT ngày 25/12/2017 của Sở Kế hoạch Đầu tư tỉnh Quảng Ninh. UBND tỉnh Quảng Ninh đã thu hồi đất theo Quyết định số 44/QĐ-UBND ngày 10/01/2018. Công ty đang phối hợp với Trung tâm phát triển quỹ đất huyện Hoành Bồ để bàn giao đất và hoàn các khoản chi phí đã đầu tư.'),
('VHL_2021_consolidated_inventory_7', 'VHL', 2021, 'consolidated', 'Chi phí xây dựng cơ bản dở dang', 'construction_in_progress', 166533637.0, 0.0, 'Chi phí xây dựng cơ bản dở dang tại ngày 31/12/2021 giảm mạnh từ 2.842.332.183 VNĐ đầu năm'),
('VHL_2020_consolidated_inventory_0', 'VHL', 2020, 'consolidated', 'Nguyên liệu, vật liệu', 'raw_material', 254016967304.0, 0.0, 'Nguyên liệu, vật liệu phục vụ sản xuất gạch ngói đất sét nung'),
('VHL_2020_consolidated_inventory_1', 'VHL', 2020, 'consolidated', 'Thành phẩm', 'finished_goods', 147119460664.0, 9650643541.0, 'Thành phẩm gạch, ngói đất sét nung và hàng hóa khác'),
('VHL_2020_consolidated_inventory_2', 'VHL', 2020, 'consolidated', 'Chi phí sản xuất kinh doanh dở dang', 'construction_in_progress', 13139985689.0, 0.0, 'Chi phí sản xuất kinh doanh dở dang tại các nhà máy'),
('VHL_2020_consolidated_inventory_3', 'VHL', 2020, 'consolidated', 'Dự án Khu dân cư, tái định cư giải phóng mặt bằng mỏ sét Xích Thổ', 'real_estate_project', 2354667273.0, 0.0, 'Dự án xây dựng khu dân cư, tái định cư cho các hộ dân bị thu hồi đất tại xã Thống Nhất, huyện Hoành Bồ, tỉnh Quảng Ninh. Tổng mức đầu tư 35,699 tỷ đồng với quy mô 18,7 ha, triển khai từ năm 2016'),
