('VHL_2020_parent_inventory_0', 'VHL', 2020, 'parent', 'Nguyên liệu, vật liệu', 'raw_material', 156679167505.0, 0.0, 'Bao gồm nguyên liệu, vật liệu và công cụ dụng cụ'),
('VHL_2020_parent_inventory_1', 'VHL', 2020, 'parent', 'Thành phẩm', 'finished_goods', 129957027103.0, 9650643541.0, 'Thành phẩm tồn kho'),
('VHL_2020_parent_inventory_2', 'VHL', 2020, 'parent', 'Dự án Khu dân cư, tái định cư giải phóng mặt bằng mỏ sét Xích Thổ', 'real_estate_project', 2354667273.0, 0.0, 'Dự án triển khai từ năm 2016, mục đích xây dựng khu dân cư, tái định cư cho hộ dân. Dự án đã bị thu hồi đất và đang chờ xử lý.'),
('VHL_2020_parent_inventory_3', 'VHL', 2020, 'parent', 'Dự án Cảng xuất hàng hóa - Nhà máy Gạch Tiêu Giao', 'construction_in_progress', 321131273.0, 0.0, 'Dự án triển khai theo 3 giai đoạn, dự kiến hoàn thành năm 2021, hiện đang trong giai đoạn ban đầu.'),
('VHL_2018_consolidated_inventory_0', 'VHL', 2018, 'consolidated', 'Nguyên liệu, vật liệu', 'raw_material', 264792158996.0, 4316797795.0, 'Nguyên liệu chính cho sản xuất gạch, ngói đất sét nung'),
('VHL_2018_consolidated_inventory_1', 'VHL', 2018, 'consolidated', 'Thành phẩm', 'finished_goods', 109323836217.0, 7090314546.0, 'Sản phẩm gạch, ngói đất sét nung thành phẩm'),
('VHL_2018_consolidated_inventory_2', 'VHL', 2018, 'consolidated', 'Dự án Xây dựng Khu dân cư và Nhà ở tập thể tại phường Giếng Đáy', 'real_estate_project', 7869559466.0, 0.0, 'Dự án xây dựng cơ sở hạ tầng để bán cho CBCNV, đã cơ bản hoàn thành, chờ phê duyệt để chuyển nhượng'),
('VHL_2018_consolidated_inventory_3', 'VHL', 2018, 'consolidated', 'Dự án Cảng xuất hàng hóa - Nhà máy gạch Tiêu Giao', 'construction_in_progress', 321131273.0, 0.0, 'Dự án xây dựng cảng xuất hàng hóa, đang ở giai đoạn ban đầu'),
('VHL_2018_parent_inventory_0', 'VHL', 2018, 'parent', 'Nguyên liệu, vật liệu', 'raw_material', 188615900261.0, 4316797795.0, 'Nguyên liệu chính là đất sét phục vụ sản xuất vật liệu xây dựng, được khai thác từ các mỏ sét tại Quảng Ninh và Đông Triều'),
('VHL_2018_parent_inventory_1', 'VHL', 2018, 'parent', 'Thành phẩm', 'finished_goods', 101609726061.0, 7090314546.0, 'Sản phẩm gạch ngói đất sét nung hoàn thành, bao gồm hàng nội địa và xuất khẩu'),
('VHL_2018_parent_inventory_2', 'VHL', 2018, 'parent', 'Chi phí sản xuất kinh doanh dở dang', 'construction_in_progress', 13735189118.0, 0.0, 'Chi phí sản xuất kinh doanh dở dang được xác định theo tỷ lệ sản phẩm hoàn thành tương đương'),
('VHL_2018_parent_inventory_3', 'VHL', 2018, 'parent', 'Dự án Xây dựng Khu dân cư và Nhà ở tập thể tại phường Giếng Đáy, thành phố Hạ Long', 'real_estate_project', 7869559466.0, 0.0, 'Tổng mức đầu tư 12.945 tỷ đồng, triển khai từ 2012. Dự án cơ bản đã hoàn thành, đang chờ Tổng Công ty Viglacera phê duyệt để chuyển nhượng cho CBCNV và các Công ty liên kết'),
('VHL_2018_parent_inventory_4', 'VHL', 2018, 'parent', 'Dự án Khu dân cư, tái định cư giải phóng mặt bằng mô sét Xích Thổ', 'real_estate_project', 2354667273.0, 0.0, 'Tổng mức đầu tư 35.699 tỷ đồng, triển khai từ 2016. UBND tỉnh Quảng Ninh xác định dự án không thuộc Nhà nước thu hồi đất, Công ty đang đầu tư hạ tầng diện tích 50.417,5 m² để bàn giao cho huyện Hoành Bồ'),
('VHL_2018_parent_inventory_5', 'VHL', 2018, 'parent', 'Dự án Xây dựng bến bãi Xí nghiệp nguyên liệu tạm tại sông Mần - huyện Hoành Bồ', 'real_estate_project', 1548921898.0, 0.0, 'Tổng mức đầu tư 36.026.828.000 VND, triển khai theo 3 giai đoạn dự kiến hoàn thành năm 2020. Đang ở giai đoạn ban đầu, chi phí chủ yếu là đền bù giải phóng mặt bằng'),
('VHL_2018_parent_inventory_6', 'VHL', 2018, 'parent', 'Cảng xuất hàng hóa - Nhà máy Gạch Tiêu Giao', 'real_estate_project', 321131273.0, 0.0, 'Tổng mức đầu tư 34.579.383.000 VND, triển khai theo 3 giai đoạn dự kiến hoàn thành năm 2020. Đang ở giai đoạn ban đầu, chi phí chủ yếu là đo đạc, biên tập bản đồ'),
('VHL_2015_consolidated_inventory_0', 'VHL', 2015, 'consolidated', 'Nguyên liệu, vật liệu', 'raw_material', 219574702080.0, 4554557578.0, NULL),
('VHL_2015_consolidated_inventory_1', 'VHL', 2015, 'consolidated', 'Công cụ, dụng cụ', 'raw_material', 3249799794.0, 0.0, NULL),
('VHL_2015_consolidated_inventory_2', 'VHL', 2015, 'consolidated', 'Chi phí sản xuất kinh doanh dở dang', 'construction_in_progress', 15268353269.0, 0.0, NULL),
('VHL_2015_consolidated_inventory_3', 'VHL', 2015, 'consolidated', 'Thành phẩm', 'finished_goods', 86655392761.0, 7494997399.0, NULL),
('VHL_2015_consolidated_inventory_4', 'VHL', 2015, 'consolidated', 'Hàng hoá', 'finished_goods', 10341178184.0, 0.0, NULL),
('VHL_2015_consolidated_inventory_5', 'VHL', 2015, 'consolidated', 'Dự án Khu 28ha Hoành Bồ', 'real_estate_project', 33642634419.0, 0.0, 'Dự án xây dựng khu dân cư cho cán bộ công nhân viên. Triển khai từ năm 2009 nhưng chưa tiếp tục do nhiều nguyên nhân khách quan. Chi phí chủ yếu là tiền sử dụng đất và chi phí san lấp mặt bằng.'),
('VHL_2015_consolidated_inventory_6', 'VHL', 2015, 'consolidated', 'Xây dựng cơ bản dở dang (Khác)', 'construction_in_progress', 58236430599.0, 0.0, 'Bao gồm nhiều hạng mục tại các nhà máy khác nhau như Cảng xuất hàng - Nhà máy Gạch Tiêu Giao, Trạm Khí hóa than - Nhà máy Gạch Giếng Đáy, Bãi Xuất nhập Nguyên liệu - Nhà máy Gạch Hoành Bổ...'),
('VHL_2015_parent_inventory_0', 'VHL', 2015, 'parent', 'Nguyên liệu, vật liệu', 'raw_material', 178252372728.0, 4554557578.0, 'Nguyên vật liệu sản xuất vật liệu xây dựng từ đất sét'),
('VHL_2015_parent_inventory_1', 'VHL', 2015, 'parent', 'Thành phẩm', 'finished_goods', 72484993366.0, 7494997399.0, 'Gạch ngói đất sét nung và các sản phẩm vật liệu xây dựng'),
('VHL_2015_parent_inventory_2', 'VHL', 2015, 'parent', 'Chi phí sản xuất kinh doanh dở dang', 'construction_in_progress', 14339451558.0, 0.0, 'Chi phí sản xuất kinh doanh dở dang tại các nhà máy'),
('VHL_2015_parent_inventory_3', 'VHL', 2015, 'parent', 'Dự án Khu 28ha Hoành Bồ', 'real_estate_project', 33642634419.0, 0.0, 'Dự án xây dựng khu dân cư cho cán bộ công nhân viên, triển khai từ năm 2009 nhưng bị đình trệ do thiếu vốn và chưa được Đại hội đồng cổ đông đồng ý. Chi phí phát sinh chủ yếu là tiền sử dụng đất và chi phí san lấp mặt bằng.'),
('VHL_2015_parent_inventory_4', 'VHL', 2015, 'parent', 'Trạm Khí hóa than - Nhà máy Gạch Giếng Đáy', 'construction_in_progress', 12779365651.0, 0.0, 'Dự án xây dựng trạm khí hóa than tại nhà máy gạch Giếng Đáy'),
