('VHL_2015_parent_inventory_6', 'VHL', 2015, 'parent', 'Cảng xuất hàng - Nhà máy Gạch Tiêu Giao', 'construction_in_progress', 50188182.0, 0.0, 'Dự án tạm dừng thực hiện và tìm đối tác để chuyển nhượng'),
('VHL_2015_parent_inventory_7', 'VHL', 2015, 'parent', 'Bãi Xuất nhập Nguyên liệu - Nhà máy Gạch Hoành Bồ', 'construction_in_progress', 1444603716.0, 0.0, 'Dự án tạm dừng thực hiện và tìm đối tác để chuyển nhượng'),
('VHH_2025_consolidated_inventory_0', 'VHH', 2025, 'consolidated', 'Nguyên liệu, vật liệu', 'raw_material', 638067679.0, 0.0, 'Bao gồm nguyên vật liệu phục vụ sản xuất bê tông thương phẩm'),
('VHH_2025_consolidated_inventory_1', 'VHH', 2025, 'consolidated', 'Dự án khu Massage - Khách sạn Heritage', 'construction_in_progress', 478473794.0, NULL, 'Chi phí ban đầu liên quan tới dự án mở rộng Khách sạn Heritage (tài sản cố định của Công ty con). Công ty dự kiến bàn giao chi phí cho Công ty con khi dự án triển khai lại. Kiểm toán viên không thu thập đủ bằng chứng về khoản chi phí này.'),
('VHH_2025_consolidated_inventory_2', 'VHH', 2025, 'consolidated', 'Dự án khai thác mỏ đá', 'construction_in_progress', 711071832.0, NULL, 'Chi phí giải tỏa, đền bù mỏ đá tại Hương Thọ, thị xã Hương Trà, Thừa Thiên Huế. Nhà nước đã giao dự án cho doanh nghiệp khác. Công ty đang đàm phán thu hồi chi phí. Kiểm toán viên không được cung cấp tài liệu liên quan.'),
('VHH_2025_consolidated_inventory_3', 'VHH', 2025, 'consolidated', 'Dự án sửa chữa, cải tạo khách sạn', 'construction_in_progress', 524971390.0, NULL, 'Chi phí xây dựng cơ bản dở dang cho dự án sửa chữa, cải tạo khách sạn'),
('VHH_2024_consolidated_inventory_0', 'VHH', 2024, 'consolidated', 'Dự án khu Massage - Khách sạn Heritage', 'construction_in_progress', 478473794.0, 0.0, 'Chi phí ban đầu liên quan tới dự án mở rộng Khách sạn Heritage (tài sản cố định của Công ty con). Công ty sẽ bàn giao các chi phí này cho Công ty con khi dự án được triển khai lại.'),
('VHH_2024_consolidated_inventory_1', 'VHH', 2024, 'consolidated', 'Dự án khai thác mỏ đá', 'construction_in_progress', 711071832.0, 0.0, 'Chi phí giải tỏa, đền bù mỏ đá tại Hương Thọ, Thừa Thiên Huế. Nhà nước đã giao dự án cho doanh nghiệp khác. Công ty đang đàm phán để thu hồi chi phí.'),
